// src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './Components/Navbar';
import Home from './Components/Home';
import About from './Components/About';
import Gallery from './Components/Gallery';
import Footer from './Components/Footer';
import FishFarming from './Components/initiatives/FishFarming';
import TableBanking from './Components/initiatives/TableBanking';
import Conservation from './Components/initiatives/Conservation';
import './App.css';

// Scroll to top on route change
import { useEffect } from 'react';
import { useLocation } from 'react-router-dom';

const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

function App() {
  return (
    <Router>
      <ScrollToTop />
      <div className="App">
        <Navbar />
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/about" element={<About />} />
          <Route path="/gallery" element={<Gallery />} />
          {/* Initiative Routes */}
          <Route path="/Compone/fish-farming" element={<FishFarming />} />
          <Route path="/Initiatives/table-banking" element={<TableBanking />} />
          <Route path="/Initiatives/conservation" element={<Conservation />} />
          {/* 404 Fallback */}
          <Route path="*" element={<h2 style={{ textAlign: 'center', margin: '40px 0' }}>404 - Page Not Found</h2>} />
        </Routes>
        <Footer />
      </div>
    </Router>
  );
}

export default App;
